#!/usr/bin/env python3
"""Apply script v2: MFL Discovery fixes — retry, backoff, league validation.

Fixes for real-world MFL behavior:
  - Retry with exponential backoff on RemoteDisconnected (3 attempts)
  - Default inter-request delay increased from 1.0s to 2.5s
  - League name extraction from TYPE=league response
  - Suspect flagging: franchise count / league name mismatch detection
  - Suspect seasons excluded from available_seasons() and ingestion
  - Server only carried forward from non-suspect results
  - CLI: --expected-franchises, --expected-name, --retries
  - 43 tests (was 35)

Updates:
  src/squadvault/mfl/discovery.py
  src/squadvault/mfl/_run_discover.py
  src/squadvault/mfl/_run_historical_ingest.py
  Tests/test_mfl_discovery_v1.py

Run: python3 apply_mfl_discovery_v2_fixes.py
Then: PYTHONPATH=src python -m pytest Tests/ -q
"""

import base64
from pathlib import Path

# --- src/squadvault/mfl/discovery.py ---
_p = Path("src/squadvault/mfl/discovery.py")
_p.parent.mkdir(parents=True, exist_ok=True)
_p.write_bytes(base64.b64decode(""))
print(f"  wrote {_p}")

# --- src/squadvault/mfl/_run_discover.py ---
_p = Path("src/squadvault/mfl/_run_discover.py")
_p.parent.mkdir(parents=True, exist_ok=True)
_p.write_bytes(base64.b64decode(""))
print(f"  wrote {_p}")

# --- src/squadvault/mfl/_run_historical_ingest.py ---
_p = Path("src/squadvault/mfl/_run_historical_ingest.py")
_p.parent.mkdir(parents=True, exist_ok=True)
_p.write_bytes(base64.b64decode(""))
print(f"  wrote {_p}")

# --- Tests/test_mfl_discovery_v1.py ---
_p = Path("Tests/test_mfl_discovery_v1.py")
_p.parent.mkdir(parents=True, exist_ok=True)
_p.write_bytes(base64.b64decode(""))
print(f"  wrote {_p}")

print()
print("Done. Run: PYTHONPATH=src python -m pytest Tests/ -q")
print("Expected: 1174 passed, 3 skipped")
print()
print("Discovery with validation:")
print("  ./scripts/py -u src/squadvault/mfl/_run_discover.py \\")
print("    --league-id 70985 --start-year 2009 --end-year 2024 \\")
print("    --expected-franchises 10 --delay 2.5")
